mapper.select:
SELECT , ep.status AS user_participant_status FROM events e LEFT JOIN event_participants ep ON ep.event_id = e.id AND ep.user_id = #{userId} WHERE e.visibility = 'public' AND e.status = 'published'
AND e.start_at >= #{from}
AND e.start_at < #{to}
AND ( e.title_hr ILIKE '%' || #{query} || '%' OR e.title_en ILIKE '%' || #{query} || '%' OR e.where_hr ILIKE '%' || #{query} || '%' OR e.where_en ILIKE '%' || #{query} || '%' OR e.address ILIKE '%' || #{query} || '%' OR e.about_hr ILIKE '%' || #{query} || '%' OR e.about_en ILIKE '%' || #{query} || '%' )
AND <= #{radiusKm}
ORDER BY
ASC,
e.start_at ASC
